// Pega a resposta bruta do agente
const raw = $json.output;

// Remove possíveis blocos de markdown (```json ... ```)
const clean = raw.replace(/^```json\s*|```$/g, '').trim();

// Faz o parse para objeto
let parsed;
try {
  parsed = JSON.parse(clean);
} catch (e) {
  throw new Error("Não foi possível converter a resposta em JSON: " + e.message + "\nConteúdo: " + clean);
}

// Retorna como JSON real
return [
  {
    json: parsed
  }
];
